INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00613', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「有一次我拜訪一位富商之妻，她愛好文學，也填詞，用字極美。然而，她那偌大的豪宅，放置著幾 件大賣場買來的傢俱，空盪盪的，毫無可觀之處。我於是暗思，美麗的詞藻固然可以堆砌成詞，但不 會有『感發』的力量，因為填詞的人並沒有被他周邊的物之美以及因著物之美而生出的『物之哀』所 感發。」 根據上文，下列何者最貼近作者的看法？', '["作者自己先有感動，下筆才能動人", "詞藻對於文學創作，通常弊大於利", "文學的意義在於從悲哀中發現美感", "人類可以憑藉藝術創作來轉化悲哀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00614', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「我不喜歡一般所謂的觀光，然而還不到痛恨的程度。我對巴黎最好的回憶不是到了羅浮宮、凱旋門、 聖母院、香榭麗舍大道，而是倚在小旅館房間窗上看街景，或在菜市場上買甜而多汁的血橘，或只是 走過街道，看擦身而過的行人，瀏覽兩旁古老建築，聽不同角落的市聲，吸取屬於巴黎的情調、節奏 和色澤。」 根據上文，最接近作者旅遊的心態是：', '["喜歡透過旅行，一一訪遊觀光名勝", "經由一般的觀光路線，發現城市的風貌", "偏好以日常生活的模式，體驗巴黎的城市之美", "藉由專業的觀光導覽，深入領略巴黎的歷史文化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00615', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「對我而言，恩斯特就是感性的化身，他有一種難以抗拒的魅力與風趣，對於世界的色彩、自它起源 以降的分門別類都了然於胸，而他也透過高彩度的攝影作品，極為生動地傳達了不同的文化。他像彗 星一樣迅速消逝，只留下長長的尾巴讓世人能理解其靈巧之處。」 根據上文，對友人攝影作品的敘述，何者正確？', '["以高彩度表達風趣", "如彗星般感性靈巧", "傳達多元文化才華洋溢", "能分門別類的運用色彩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00616', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「讀者無法喜愛新的作品，但當這作品問世二十年後卻又真誠地喜愛它，這是常有的事。作品新生命 的香味太濃了，他們虛弱的頭腦承受不了。香氣會隨時間的流逝而漸漸揮發掉，作品只有在覆滿陳年 積垢時才會被他們理解。」 根據上文，下列選項何者最符合文意？', '["作品如美酒，需要時間才能真正成熟", "讀者需要成長，才能領會作品的價值", "讀者如果真誠，未必有助於理解作品", "作品假使過於個性化，很難流傳不朽"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00617', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「臺灣這個小小的島被龐大的海洋包圍，天生離海很近，但許多人跟我一樣，喜歡海，卻又不知道那 是什麼。軍艦駛離港口後的某一刻，我第一次發現自己正從海上隔著一波又一波搖晃的藍色凝視著平 日居住的陸地。那片藍色非常巨大，照康德的說法那叫『壯美』（sublime），讓人又愛又怕的一種美。」 根據上文，下列選項何者最符合文意？', '["因為認識不足，導致人們無法體會海洋的壯美", "偌大海洋潛藏無窮的危險，實在讓人又愛又怕", "臺灣四周被海洋包圍，吸引人產生敬畏的美感", "搭船離開本島，方能認識周邊海洋的豐富生態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00618', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「有一種演員，專注於背詞，精心打造咬字、語氣、情緒，好像把臺詞背熟，是演戲唯一的功夫。他忽 略了最根本的部分：聽別人的詞。一位資深導演曾形容一群專業演員在舞臺上，如同職業球賽，每個 球員不能只顧自己的攻擊、防守位置，而要放開感官，隨時支援他人。」 上述文句表達不論在舞臺或球場等場域中，重要的參與原則是：', '["犧牲小我，完成大我", "風大就涼，人多就強", "臺上三分鐘，臺下十年功", "眾人種樹樹成林，大家栽花花才香"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00619', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「現在的工作者常常有許多機器協助工作，電腦、印表機、多功能事務機等等，我們幾乎不可能在沒 有機器協助下完成工作。與此同時，我們的工作也常常是經過設計的，每一個步驟都需要按照標準程 序，這也就代表著：就算你做得很好，但功勞在於程序設計得完善，而不是你的付出與貢獻。」 根據上文，下列選項最接近文意的是：', '["人類仰賴機器所帶來的便利生活而產生惰性", "傳統的勞動方式因為機器的便利而遭到淘汰", "人類的勞動成果經常被標準程序的效率掩蓋", "人類設計了機器和工作程序來取代勞動付出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00620', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「記憶不像是從檔案櫃裡拉出一張紙，重新提取這個事件的精確拷貝，而是重新產生運作中的記憶。 你抽出了正確的精髓，但也漏失很多細節。所以你靠著想像力，用看似可信的東西填滿。我們重組過 去，也許隨著每一次的回憶，我們甚至還把新的錯誤給補進去了，事件記憶變成了接力傳話最後卻失 真的遊戲。」 根據上文，下列選項何者最符合作者對記憶的看法？', '["真實事件中夾雜著刻意虛構的細節", "添加了未必存在但信以為真的內容", "每一次重新提取的內容都完全相同", "在重組過程中不斷釐清而趨近真實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00621', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「海洋相連，保護個別區域、單獨物種，遠遠追趕不上整體的破壞，尤其海洋物種如鯨魚、海龜具有 遠距離遷徙的習性，必須制定更全面的管理和規範。目前，各國多半只掃門前雪，全球海洋61%的公 海更是無法可管。更只有不到8%的海洋受到保護（其中6.93%屬於國家水域，廣大的公海僅有0.72% 設立為保護區）。綠色和平近年極力推動聯合國成立《全球海洋公約》，以具有法律效力的文書，約束 各政府在2030年前保護至少30%海洋，設立為保護區，為海洋生物爭取足夠的生態廊道。」 根據上文，全球海洋保護目前做到的進度是：', '["詳列海洋物種會遠距遷徙的習性", "訂定個別區域單獨物種的保護令", "召喚全球的共識以確定執行目標", "要求各國立即嚴格執行保護行動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00622', 'judicial-57f41407', 'judicial-57f41407-moex-111-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「以整體產業的角度來看，有許多方法可以減少製造多餘垃圾，比如：從設計源頭就開始減少多餘、 不必要的包裝；在設計時就考慮到產品使用後的再生、再利用，以及回收等面向；設計更有效的產品 使用後收集系統等等，以及可大幅減少製造多餘垃圾的商業模式，如專門提供合作店家可再利用的餐 盒餐具，並透過結合手機應用程式，設置多個回收據點，讓消費者毋須自備餐具，只需付押金，再用 手機上操作登記和歸還，即可享受方便美食。」 根據上文，下列選項何者正確？', '["研發新型回收工具，可以同時兼顧科技、便利與環保", "設計更環保的包裝方式，舊有的商業模式仍能繼續沿用", "從源頭思考周全的產品生命週期分析，可以減少垃圾的產生", "完整產銷鏈的產業革新可以讓生產者減少責任，同時兼顧環保"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:40+00:00", "source_pdf_sha1": "9590982026e4", "answer_pdf_sha1": "a7948f89865b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
